// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <string.h>
int main() {
    int N, Q, S, TH, i, j, k, count;
    char swearWords[100000][100], ndwList[100000][100];
    scanf("%d", &N);
    for (i = 0; i < N; i++) {
        scanf("%s", swearWords[i]);
    }
    scanf("%d", &Q);
    while (Q--) {
        scanf("%d %d", &S, &TH);
        for (i = 0; i < S; i++) {
            scanf("%s", ndwList[i]);
        }
        count = 0;
        for (i = 0; i < N; i++) {
            for (j = 0; j < S; j++) {
                if (strncmp(swearWords[i], ndwList[j], strlen(swearWords[i])) == 0) {
                    count++;
                }
            }
            if (count >= TH) {
                printf("%d\n", i + 1);
                break;
            }
        }
        if (i == N) {
            printf("-1\n");
        }
    }
    return 0;
}

