// COMPLETE, COMPILABLE Java code
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        String[] swearWords = new String[N];
        for (int i = 0; i < N; i++) {
            swearWords[i] = sc.next();
        }
        int Q = sc.nextInt();
        while (Q-- > 0) {
            int S = sc.nextInt();
            int TH = sc.nextInt();
            String[] ndwList = new String[S];
            for (int i = 0; i < S; i++) {
                ndwList[i] = sc.next();
            }
            int count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < S; j++) {
                    if (ndwList[j].startsWith(swearWords[i])) {
                        count++;
                    }
                }
                if (count >= TH) {
                    System.out.println(i + 1);
                    break;
                }
            }
            if (count < TH) {
                System.out.println(-1);
            }
        }
    }
}

